-- Propel — consolidated schema from legacy api/migrations
-- Generated by scripts/consolidate-supabase-migrations.mjs — do not edit by hand

CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ─── from api/migrations/001_schema.sql ───
-- Propel — Standalone PostgreSQL Schema
-- No Supabase dependencies. All auth handled by Propel API JWT.
-- Run via: npm run db:migrate

-- ─── Organizations ────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS organizations (
  id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  name        text        NOT NULL,
  slug        text        NOT NULL UNIQUE,
  domain      text,
  logo_url    text,
  plan        text        NOT NULL DEFAULT 'free',
  settings    jsonb       NOT NULL DEFAULT '{}',
  created_at  timestamptz NOT NULL DEFAULT now(),
  updated_at  timestamptz NOT NULL DEFAULT now()
);

-- ─── Users ───────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS users (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  email           text        NOT NULL UNIQUE,
  password_hash   text        NOT NULL,
  name            text        NOT NULL,
  role            text        NOT NULL DEFAULT 'sales_rep'
                              CHECK (role IN ('owner','admin','manager','sales_rep','viewer')),
  job_title       text,
  avatar_url      text,
  is_active       boolean     NOT NULL DEFAULT true,
  organization_id uuid        REFERENCES organizations(id) ON DELETE SET NULL,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_users_org ON users(organization_id);
CREATE INDEX IF NOT EXISTS idx_users_email ON users(email);

-- ─── Invitations ─────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS invitations (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  email           text        NOT NULL,
  role            text        NOT NULL DEFAULT 'sales_rep',
  token           text        NOT NULL UNIQUE DEFAULT replace(gen_random_uuid()::text || gen_random_uuid()::text, '-', ''),
  invited_by      uuid        REFERENCES users(id) ON DELETE SET NULL,
  status          text        NOT NULL DEFAULT 'pending',
  expires_at      timestamptz NOT NULL DEFAULT now() + interval '7 days',
  created_at      timestamptz NOT NULL DEFAULT now(),
  UNIQUE(email, organization_id)
);

-- ─── Companies ───────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS companies (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  name            text        NOT NULL,
  domain          text,
  industry        text,
  size            text,
  country         text,
  city            text,
  website         text,
  phone           text,
  revenue         numeric,
  status          text        NOT NULL DEFAULT 'prospect',
  tags            text[]      NOT NULL DEFAULT '{}',
  notes           text,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_companies_org ON companies(organization_id);

-- ─── Contacts ────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS contacts (
  id               uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id  uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  first_name       text        NOT NULL,
  last_name        text        NOT NULL DEFAULT '',
  email            text,
  phone            text,
  job_title        text,
  company_id       uuid        REFERENCES companies(id) ON DELETE SET NULL,
  status           text        NOT NULL DEFAULT 'prospect',
  type             text        NOT NULL DEFAULT 'lead' CHECK (type IN ('lead','contact')),
  source           text        NOT NULL DEFAULT 'other',
  lead_score       integer     NOT NULL DEFAULT 50,
  tags             text[]      NOT NULL DEFAULT '{}',
  notes            text,
  assigned_to      uuid        REFERENCES users(id) ON DELETE SET NULL,
  last_contacted_at timestamptz,
  linked_deals     text[]      NOT NULL DEFAULT '{}',
  created_at       timestamptz NOT NULL DEFAULT now(),
  updated_at       timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_contacts_org ON contacts(organization_id);
CREATE INDEX IF NOT EXISTS idx_contacts_company ON contacts(company_id);
CREATE INDEX IF NOT EXISTS idx_contacts_email ON contacts(organization_id, email);

-- ─── Deals ───────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS deals (
  id                  uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id     uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  title               text        NOT NULL,
  value               numeric     NOT NULL DEFAULT 0,
  currency            text        NOT NULL DEFAULT 'USD',
  stage               text        NOT NULL DEFAULT 'lead',
  status              text        NOT NULL DEFAULT 'open' CHECK (status IN ('open','won','lost')),
  contact_id          uuid        REFERENCES contacts(id) ON DELETE SET NULL,
  company_id          uuid        REFERENCES companies(id) ON DELETE SET NULL,
  owner_id            uuid        REFERENCES users(id) ON DELETE SET NULL,
  assigned_to         uuid        REFERENCES users(id) ON DELETE SET NULL,
  expected_close_date date,
  closed_at           timestamptz,
  quote_items         jsonb       NOT NULL DEFAULT '[]',
  tags                text[]      NOT NULL DEFAULT '{}',
  notes               text,
  created_at          timestamptz NOT NULL DEFAULT now(),
  updated_at          timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_deals_org ON deals(organization_id);
CREATE INDEX IF NOT EXISTS idx_deals_stage ON deals(organization_id, stage);

-- ─── Activities ──────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS activities (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  type            text        NOT NULL CHECK (type IN ('call','email','meeting','task','note','demo','follow_up')),
  subject         text        NOT NULL,
  description     text        NOT NULL DEFAULT '',
  outcome         text,
  due_date        timestamptz,
  completed_at    timestamptz,
  status          text        NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','completed','cancelled')),
  contact_id      uuid        REFERENCES contacts(id) ON DELETE SET NULL,
  company_id      uuid        REFERENCES companies(id) ON DELETE SET NULL,
  deal_id         uuid        REFERENCES deals(id) ON DELETE SET NULL,
  created_by      text,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_activities_org ON activities(organization_id);
CREATE INDEX IF NOT EXISTS idx_activities_deal ON activities(deal_id);
CREATE INDEX IF NOT EXISTS idx_activities_contact ON activities(contact_id);

-- ─── Notifications ───────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS notifications (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  type            text        NOT NULL,
  title           text        NOT NULL,
  message         text        NOT NULL DEFAULT '',
  entity_type     text,
  entity_id       text,
  user_id         text        NOT NULL DEFAULT 'system',
  triggered_by    text,
  is_read         boolean     NOT NULL DEFAULT false,
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_notifications_org_user ON notifications(organization_id, user_id);

-- ─── Audit Log ───────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS audit_log (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  action          text        NOT NULL,
  entity_type     text        NOT NULL,
  entity_id       text        NOT NULL,
  entity_name     text        NOT NULL DEFAULT '',
  details         text        NOT NULL DEFAULT '',
  user_id         text        NOT NULL DEFAULT 'system',
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_audit_org ON audit_log(organization_id, created_at DESC);

-- ─── Products ────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS products (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  name            text        NOT NULL,
  description     text,
  sku             text,
  price           numeric     NOT NULL DEFAULT 0,
  currency        text        NOT NULL DEFAULT 'EUR',
  category        text,
  is_active       boolean     NOT NULL DEFAULT true,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

-- ─── Email Templates ─────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS email_templates (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  name            text        NOT NULL,
  subject         text        NOT NULL,
  body            text        NOT NULL DEFAULT '',
  category        text        NOT NULL DEFAULT 'general'
                              CHECK (category IN ('outreach','follow_up','proposal','onboarding','general')),
  variables       text[]      NOT NULL DEFAULT '{}',
  usage_count     integer     NOT NULL DEFAULT 0,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

-- ─── Quick Replies ───────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS quick_replies (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  user_id         uuid        REFERENCES users(id) ON DELETE SET NULL,
  title           text        NOT NULL,
  body            text        NOT NULL DEFAULT '',
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

-- ─── Sales Goals ─────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS sales_goals (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  user_id         uuid        REFERENCES users(id) ON DELETE SET NULL,
  type            text        NOT NULL,
  target          numeric     NOT NULL DEFAULT 0,
  current         numeric     NOT NULL DEFAULT 0,
  period          text        NOT NULL DEFAULT 'monthly',
  start_date      date        NOT NULL,
  end_date        date        NOT NULL,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

-- ─── Automation Rules ────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS automation_rules (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  name            text        NOT NULL,
  description     text        NOT NULL DEFAULT '',
  is_active       boolean     NOT NULL DEFAULT true,
  trigger         jsonb       NOT NULL DEFAULT '{}',
  actions         jsonb       NOT NULL DEFAULT '[]',
  execution_count integer     NOT NULL DEFAULT 0,
  last_executed_at timestamptz,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

-- ─── Automation Executions ───────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS automation_executions (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  rule_id         uuid        REFERENCES automation_rules(id) ON DELETE SET NULL,
  trigger_type    text        NOT NULL,
  status          text        NOT NULL DEFAULT 'success' CHECK (status IN ('success','error')),
  context         jsonb       NOT NULL DEFAULT '{}',
  result          jsonb       NOT NULL DEFAULT '{}',
  error_message   text,
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_auto_exec_org ON automation_executions(organization_id, created_at DESC);

-- ─── Email Sequences ─────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS email_sequences (
  id                          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id             uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  name                        text        NOT NULL,
  description                 text        NOT NULL DEFAULT '',
  steps                       jsonb       NOT NULL DEFAULT '[]',
  flow_definition             jsonb,
  created_by                  uuid        REFERENCES users(id) ON DELETE SET NULL,
  is_active                   boolean     NOT NULL DEFAULT true,
  enrolled_count              integer     NOT NULL DEFAULT 0,
  stop_on_contact_reply       boolean     NOT NULL DEFAULT true,
  enrollment_start_delay_days integer     NOT NULL DEFAULT 0,
  created_at                  timestamptz NOT NULL DEFAULT now()
);

-- ─── Sequence Enrollments ────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS sequence_enrollments (
  id                  uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id     uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  sequence_id         uuid        NOT NULL REFERENCES email_sequences(id) ON DELETE CASCADE,
  contact_id          uuid        REFERENCES contacts(id) ON DELETE SET NULL,
  contact_name        text        NOT NULL,
  current_step        integer     NOT NULL DEFAULT 0,
  current_node_id     text,
  ab_variant          text        CHECK (ab_variant IN ('a','b')),
  status              text        NOT NULL DEFAULT 'active'
                                  CHECK (status IN ('active','paused','completed','unenrolled','replied')),
  enrolled_at         timestamptz NOT NULL DEFAULT now(),
  next_step_at        timestamptz,
  completed_at        timestamptz,
  last_sent_thread_id text,
  last_sent_message_id text
);

CREATE INDEX IF NOT EXISTS idx_seq_enr_org ON sequence_enrollments(organization_id);
CREATE INDEX IF NOT EXISTS idx_seq_enr_contact ON sequence_enrollments(contact_id);

-- ─── Custom Field Definitions ────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS custom_field_definitions (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  entity_type     text        NOT NULL,
  label           text        NOT NULL,
  field_type      text        NOT NULL DEFAULT 'text',
  placeholder     text,
  options         jsonb,
  required        boolean     NOT NULL DEFAULT false,
  "order"         integer     NOT NULL DEFAULT 0,
  is_active       boolean     NOT NULL DEFAULT true,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

-- ─── Custom Field Values ─────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS custom_field_values (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  entity_id       text        NOT NULL,
  field_id        uuid        NOT NULL REFERENCES custom_field_definitions(id) ON DELETE CASCADE,
  value           jsonb,
  UNIQUE(entity_id, field_id)
);

-- ─── Custom Field i18n ───────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS custom_field_definition_i18n (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  field_id        uuid        NOT NULL REFERENCES custom_field_definitions(id) ON DELETE CASCADE,
  language_code   text        NOT NULL,
  label           text        NOT NULL,
  placeholder     text,
  options         jsonb,
  UNIQUE(field_id, language_code)
);

-- ─── Leads ───────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS leads (
  id                   uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id      uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  first_name           text        NOT NULL,
  last_name            text        NOT NULL,
  email                text        NOT NULL,
  phone                text,
  company_name         text,
  job_title            text,
  source               text        NOT NULL DEFAULT 'website',
  status               text        NOT NULL DEFAULT 'open'
                                   CHECK (status IN ('open','contacted','qualified','disqualified','converted')),
  lifecycle_stage      text        NOT NULL DEFAULT 'lead'
                                   CHECK (lifecycle_stage IN ('lead','mql','sql','opportunity','customer','evangelist')),
  score                integer     NOT NULL DEFAULT 0,
  assigned_to          uuid        REFERENCES users(id) ON DELETE SET NULL,
  owner_user_id        uuid        REFERENCES users(id) ON DELETE SET NULL,
  tags                 jsonb       NOT NULL DEFAULT '[]',
  notes                text,
  last_engaged_at      timestamptz,
  converted_contact_id uuid        REFERENCES contacts(id) ON DELETE SET NULL,
  converted_company_id uuid        REFERENCES companies(id) ON DELETE SET NULL,
  converted_deal_id    uuid        REFERENCES deals(id) ON DELETE SET NULL,
  created_at           timestamptz NOT NULL DEFAULT now(),
  updated_at           timestamptz NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX IF NOT EXISTS leads_unique_email_per_org ON leads(organization_id, lower(email));
CREATE INDEX IF NOT EXISTS idx_leads_org ON leads(organization_id, score DESC);

-- ─── Lead Events ─────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS lead_events (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  lead_id         uuid        NOT NULL REFERENCES leads(id) ON DELETE CASCADE,
  event_type      text        NOT NULL,
  metadata        jsonb       NOT NULL DEFAULT '{}',
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_lead_events_lead ON lead_events(lead_id, created_at DESC);

-- ─── Lead Score Snapshots ────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS lead_score_snapshots (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  lead_id         uuid        NOT NULL REFERENCES leads(id) ON DELETE CASCADE,
  score           integer     NOT NULL,
  reason          text,
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_lead_snapshots_lead ON lead_score_snapshots(lead_id, created_at ASC);

-- ─── Lead Scoring Rules ──────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS lead_scoring_rules (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  key             text        NOT NULL,
  points          integer     NOT NULL DEFAULT 0,
  is_enabled      boolean     NOT NULL DEFAULT true,
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now(),
  UNIQUE(organization_id, key)
);

-- ─── from api/migrations/002_indexes_and_perf.sql ───
-- ─────────────────────────────────────────────────────────────────────────────
-- Migration 002 — Indexes, performance fixes, and Row Level Security
-- Apply with: psql $DATABASE_URL -f migrations/002_indexes_and_perf.sql
--
-- (index built inline for Supabase migrations)
-- acquiring an AccessShareLock that would block reads or writes.
-- (index built inline for Supabase migrations)
-- outside of BEGIN/COMMIT or use psql directly.
-- ─────────────────────────────────────────────────────────────────────────────

-- ─── 1. pg_trgm extension ────────────────────────────────────────────────────
-- Required for GIN trigram indexes that make ILIKE fast.
CREATE EXTENSION IF NOT EXISTS pg_trgm;


-- ─── 2. GIN trigram indexes for ILIKE search columns ─────────────────────────

-- contacts: first_name, last_name, email, phone
CREATE INDEX IF NOT EXISTS idx_trgm_contacts_first_name
  ON contacts USING GIN (first_name gin_trgm_ops);

CREATE INDEX IF NOT EXISTS idx_trgm_contacts_last_name
  ON contacts USING GIN (last_name gin_trgm_ops);

CREATE INDEX IF NOT EXISTS idx_trgm_contacts_email
  ON contacts USING GIN (email gin_trgm_ops);

CREATE INDEX IF NOT EXISTS idx_trgm_contacts_phone
  ON contacts USING GIN (phone gin_trgm_ops);

-- companies: name
CREATE INDEX IF NOT EXISTS idx_trgm_companies_name
  ON companies USING GIN (name gin_trgm_ops);

-- deals: title
CREATE INDEX IF NOT EXISTS idx_trgm_deals_title
  ON deals USING GIN (title gin_trgm_ops);

-- leads: first_name, last_name, email (leads list is a hot search path too)
CREATE INDEX IF NOT EXISTS idx_trgm_leads_first_name
  ON leads USING GIN (first_name gin_trgm_ops);

CREATE INDEX IF NOT EXISTS idx_trgm_leads_last_name
  ON leads USING GIN (last_name gin_trgm_ops);

CREATE INDEX IF NOT EXISTS idx_trgm_leads_email
  ON leads USING GIN (email gin_trgm_ops);


-- ─── 3. B-tree covering indexes on hot tenant-scoped foreign keys ─────────────
-- Pattern: WHERE organization_id = $1 AND <fk> = $2
-- 001_schema.sql already covers the most basic (org, email) and (org) cases;
-- the entries below fill in everything that was missed.

-- contacts.assigned_to scoped to org
CREATE INDEX IF NOT EXISTS idx_contacts_org_assigned
  ON contacts(organization_id, assigned_to);

-- contacts.company_id scoped to org (001 has idx_contacts_company without org)
CREATE INDEX IF NOT EXISTS idx_contacts_org_company
  ON contacts(organization_id, company_id);

-- deals.contact_id scoped to org
CREATE INDEX IF NOT EXISTS idx_deals_org_contact
  ON deals(organization_id, contact_id);

-- deals.company_id scoped to org
CREATE INDEX IF NOT EXISTS idx_deals_org_company
  ON deals(organization_id, company_id);

-- deals.owner_id scoped to org
CREATE INDEX IF NOT EXISTS idx_deals_org_owner
  ON deals(organization_id, owner_id);

-- deals.assigned_to scoped to org
CREATE INDEX IF NOT EXISTS idx_deals_org_assigned
  ON deals(organization_id, assigned_to);

-- activities.company_id scoped to org
CREATE INDEX IF NOT EXISTS idx_activities_org_company
  ON activities(organization_id, company_id);

-- activities.contact_id scoped to org (001 has idx_activities_contact without org)
CREATE INDEX IF NOT EXISTS idx_activities_org_contact
  ON activities(organization_id, contact_id);

-- activities.deal_id scoped to org (001 has idx_activities_deal without org)
CREATE INDEX IF NOT EXISTS idx_activities_org_deal
  ON activities(organization_id, deal_id);

-- sequence_enrollments.sequence_id scoped to org
CREATE INDEX IF NOT EXISTS idx_seq_enr_org_sequence
  ON sequence_enrollments(organization_id, sequence_id);

-- sequence_enrollments.contact_id scoped to org (001 has it without org)
CREATE INDEX IF NOT EXISTS idx_seq_enr_org_contact
  ON sequence_enrollments(organization_id, contact_id);

-- leads.assigned_to scoped to org
CREATE INDEX IF NOT EXISTS idx_leads_org_assigned
  ON leads(organization_id, assigned_to);

-- leads.owner_user_id scoped to org
CREATE INDEX IF NOT EXISTS idx_leads_org_owner
  ON leads(organization_id, owner_user_id);

-- lead_events.organization_id (scan by org before filtering by lead)
CREATE INDEX IF NOT EXISTS idx_lead_events_org
  ON lead_events(organization_id, lead_id, created_at DESC);

-- quick_replies.user_id scoped to org
CREATE INDEX IF NOT EXISTS idx_quick_replies_org_user
  ON quick_replies(organization_id, user_id);

-- sales_goals.user_id scoped to org
CREATE INDEX IF NOT EXISTS idx_sales_goals_org_user
  ON sales_goals(organization_id, user_id);

-- automation_executions.rule_id scoped to org
CREATE INDEX IF NOT EXISTS idx_auto_exec_org_rule
  ON automation_executions(organization_id, rule_id);

-- custom_field_values.field_id scoped to org
CREATE INDEX IF NOT EXISTS idx_cfv_org_field
  ON custom_field_values(organization_id, field_id);

-- notifications: unread lookup (hot path for notification badge)
CREATE INDEX IF NOT EXISTS idx_notifications_unread
  ON notifications(organization_id, user_id, is_read)
  WHERE is_read = false;


-- ─── 4. Composite indexes for common list query patterns ─────────────────────

-- (organization_id, created_at DESC) — default sort on all list endpoints
CREATE INDEX IF NOT EXISTS idx_contacts_org_created
  ON contacts(organization_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_deals_org_created
  ON deals(organization_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_companies_org_created
  ON companies(organization_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_activities_org_created
  ON activities(organization_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_leads_org_created
  ON leads(organization_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_sequences_org_created
  ON email_sequences(organization_id, created_at DESC);

-- (organization_id, status) — filtered list views
CREATE INDEX IF NOT EXISTS idx_deals_org_status
  ON deals(organization_id, status);

CREATE INDEX IF NOT EXISTS idx_contacts_org_status
  ON contacts(organization_id, status);

CREATE INDEX IF NOT EXISTS idx_leads_org_status
  ON leads(organization_id, status);

-- (organization_id, assigned_to) — "my items" filter used on every list view
CREATE INDEX IF NOT EXISTS idx_deals_org_assigned_to
  ON deals(organization_id, assigned_to);

CREATE INDEX IF NOT EXISTS idx_contacts_org_assigned_to
  ON contacts(organization_id, assigned_to);

CREATE INDEX IF NOT EXISTS idx_leads_org_assigned_to
  ON leads(organization_id, assigned_to);


-- ─── 5. Partial index for active email sequences ──────────────────────────────
-- email_sequences uses is_active boolean (not a status text column).
-- This index covers the common "fetch active sequences" query and is kept small
-- because inactive sequences are excluded from the index entirely.
CREATE INDEX IF NOT EXISTS idx_sequences_active
  ON email_sequences(organization_id, created_at DESC)
  WHERE is_active = true;

-- Active sequence enrollments — polled by the sequence runner on every tick
CREATE INDEX IF NOT EXISTS idx_seq_enr_active_next_step
  ON sequence_enrollments(organization_id, next_step_at ASC)
  WHERE status = 'active';

-- ─── from api/migrations/003_gmail_webhooks_tracking.sql ───
-- Migration 003: Gmail tokens, thread links, webhook subscriptions, email tracking

-- ─── Gmail tokens ────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS gmail_tokens (
  id                   uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id              uuid        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  organization_id      uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  email_address        text        NOT NULL,
  refresh_token        text,
  refresh_token_cipher text,
  access_token         text,
  token_expiry         timestamptz,
  scopes               text,
  google_sub           text,
  name                 text,
  avatar_url           text,
  is_active            boolean     NOT NULL DEFAULT true,
  created_at           timestamptz NOT NULL DEFAULT now(),
  updated_at           timestamptz NOT NULL DEFAULT now(),
  UNIQUE (user_id, organization_id)
);

CREATE INDEX IF NOT EXISTS idx_gmail_tokens_org ON gmail_tokens(organization_id);

-- ─── Gmail thread links ───────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS gmail_thread_links (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  thread_id       text        NOT NULL,
  user_id         uuid        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  contact_id      uuid        REFERENCES contacts(id) ON DELETE SET NULL,
  company_id      uuid        REFERENCES companies(id) ON DELETE SET NULL,
  deal_id         uuid        REFERENCES deals(id) ON DELETE SET NULL,
  source          text        NOT NULL DEFAULT 'manual' CHECK (source IN ('auto', 'manual')),
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now(),
  UNIQUE (thread_id, user_id, organization_id)
);

CREATE INDEX IF NOT EXISTS idx_gmail_thread_links_org_user ON gmail_thread_links(organization_id, user_id);
CREATE INDEX IF NOT EXISTS idx_gmail_thread_links_thread ON gmail_thread_links(thread_id);

-- ─── Webhook subscriptions ───────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS webhook_subscriptions (
  id                  uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id     uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  created_by          uuid        REFERENCES users(id) ON DELETE SET NULL,
  name                text        NOT NULL,
  target_url          text        NOT NULL,
  enabled             boolean     NOT NULL DEFAULT true,
  event_filters       text[]      NOT NULL DEFAULT ARRAY['*']::text[],
  custom_headers      jsonb       NOT NULL DEFAULT '{}',
  schema_version      smallint    NOT NULL DEFAULT 1,
  last_delivery_at    timestamptz,
  last_http_status    integer,
  last_delivery_error text,
  created_at          timestamptz NOT NULL DEFAULT now(),
  updated_at          timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT webhook_subscriptions_https CHECK (target_url ~ '^https://')
);

CREATE INDEX IF NOT EXISTS idx_webhook_subscriptions_org
  ON webhook_subscriptions(organization_id) WHERE enabled = true;

CREATE TABLE IF NOT EXISTS webhook_subscription_secrets (
  subscription_id uuid PRIMARY KEY REFERENCES webhook_subscriptions(id) ON DELETE CASCADE,
  signing_secret  text NOT NULL
);

-- ─── Email tracking ───────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS email_tracking_messages (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  email_id        text        NOT NULL,
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  user_id         uuid        REFERENCES users(id) ON DELETE SET NULL,
  contact_id      uuid        REFERENCES contacts(id) ON DELETE SET NULL,
  company_id      uuid        REFERENCES companies(id) ON DELETE SET NULL,
  deal_id         uuid        REFERENCES deals(id) ON DELETE SET NULL,
  open_token      text        NOT NULL UNIQUE DEFAULT gen_random_uuid()::text,
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_email_tracking_messages_org
  ON email_tracking_messages(organization_id, email_id);

CREATE TABLE IF NOT EXISTS email_tracking_links (
  id                   uuid  PRIMARY KEY DEFAULT gen_random_uuid(),
  tracking_message_id  uuid  NOT NULL REFERENCES email_tracking_messages(id) ON DELETE CASCADE,
  email_id             text  NOT NULL,
  organization_id      uuid  NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  contact_id           uuid  REFERENCES contacts(id) ON DELETE SET NULL,
  original_url         text  NOT NULL,
  click_token          text  NOT NULL UNIQUE DEFAULT gen_random_uuid()::text,
  created_at           timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_email_tracking_links_org
  ON email_tracking_links(organization_id, email_id);

CREATE TABLE IF NOT EXISTS email_tracking_events (
  id                  uuid  PRIMARY KEY DEFAULT gen_random_uuid(),
  tracking_message_id uuid  NOT NULL REFERENCES email_tracking_messages(id) ON DELETE CASCADE,
  link_id             uuid  REFERENCES email_tracking_links(id) ON DELETE SET NULL,
  email_id            text  NOT NULL,
  organization_id     uuid  NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  contact_id          uuid  REFERENCES contacts(id) ON DELETE SET NULL,
  event_type          text  NOT NULL CHECK (event_type IN ('open', 'click')),
  user_agent          text,
  ip_hash             text,
  created_at          timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_email_tracking_events_org
  ON email_tracking_events(organization_id, email_id, event_type, created_at DESC);

