-- ─── from api/migrations/019_mfa.sql ───
-- ─────────────────────────────────────────────────────────────────────────────
-- 019_mfa.sql — TOTP multi-factor authentication
--
-- mfa_secret_cipher holds the base32 TOTP secret encrypted with AES-256-GCM
-- (services/tokenCipher.ts), so a DB compromise alone does not expose seeds.
-- mfa_enabled is only set true after the user proves possession with a valid
-- code (POST /auth/mfa/enable).
-- ─────────────────────────────────────────────────────────────────────────────
ALTER TABLE users ADD COLUMN IF NOT EXISTS mfa_enabled boolean NOT NULL DEFAULT false;
ALTER TABLE users ADD COLUMN IF NOT EXISTS mfa_secret_cipher text;

-- ─── from api/migrations/020_security_events.sql ───
-- ─────────────────────────────────────────────────────────────────────────────
-- 020_security_events.sql — tamper-evident security event log (SOC2 CC7 / ISO A.12.4)
--
-- Append-only record of authentication & account-security events. Distinct from
-- audit_log (which is org-scoped business activity): security_events also captures
-- events with no org/actor context (e.g. a failed login for an unknown email),
-- so organization_id and actor_user_id are NULLABLE.
-- ─────────────────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS security_events (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  event_type      text        NOT NULL,
  actor_user_id   uuid        REFERENCES users(id) ON DELETE SET NULL,
  actor_email     text,
  organization_id uuid        REFERENCES organizations(id) ON DELETE SET NULL,
  ip              text,
  user_agent      text,
  detail          text        NOT NULL DEFAULT '',
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_security_events_created ON security_events (created_at DESC);
CREATE INDEX IF NOT EXISTS idx_security_events_actor   ON security_events (actor_user_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_security_events_org     ON security_events (organization_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_security_events_type    ON security_events (event_type, created_at DESC);

-- ─── from api/migrations/021_item_updates.sql ───
-- Monday-style collaboration: threaded "Updates" on CRM items (contacts, companies,
-- deals, leads). Each update can be a reply (parent_id) and can @mention org members.
-- App-layer org scoping is the authoritative control; RLS mirrors the 018_ai pattern
-- as opt-in defense-in-depth (see docs/adr/0001-tenant-isolation-and-rls.md).

CREATE TABLE IF NOT EXISTS item_updates (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid        NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,
  entity_type     text        NOT NULL CHECK (entity_type IN ('contact','company','deal','lead')),
  entity_id       text        NOT NULL,
  parent_id       uuid        REFERENCES item_updates(id) ON DELETE CASCADE,
  author_id       uuid        REFERENCES users(id) ON DELETE SET NULL,
  body            text        NOT NULL,
  mentions        jsonb       NOT NULL DEFAULT '[]',
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now(),
  deleted_at      timestamptz
);

CREATE INDEX IF NOT EXISTS idx_item_updates_entity
  ON item_updates (organization_id, entity_type, entity_id, created_at DESC)
  WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_item_updates_parent
  ON item_updates (parent_id) WHERE parent_id IS NOT NULL;

-- ── RLS (opt-in defense-in-depth) ────────────────────────────────────────────
ALTER TABLE item_updates ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS rls_item_updates_org ON item_updates;
CREATE POLICY rls_item_updates_org ON item_updates
  USING (organization_id = current_setting('app.current_org_id', true)::uuid);

