CREATE POLICY rls_bookings_org ON bookings USING (organization_id = current_setting('app.current_org_id', true)::uuid);

-- ─── from api/migrations/026_align_deal_terminal_stage_ids.sql ───
-- 026: Align deal terminal stage ids with the app's canonical 'closed_won'/'closed_lost'.
--
-- The frontend (kanban/list/calendar/timeline, dealsStore, deal-health logic),
-- deals.ts status mapping, and analytics.ts all key off 'closed_won'/'closed_lost',
-- but the default pipeline seeded ids 'won'/'lost'. That mismatch meant won/lost
-- deals were never counted, Mark-Won/Lost made cards vanish, and win/loss
-- notifications/automations never fired. pipelines.ts now seeds 'closed_won'/
-- 'closed_lost'; this migration realigns any already-seeded data.

-- Existing deals carrying the old terminal stage ids.
UPDATE deals SET stage = 'closed_won'  WHERE stage = 'won';
UPDATE deals SET stage = 'closed_lost' WHERE stage = 'lost';

-- Existing pipeline stage definitions (jsonb array of {id,name,order,...}).
-- Rebuild each array, rewriting the terminal stage ids while preserving order.
UPDATE pipelines p
SET stages = (
  SELECT jsonb_agg(
    CASE
      WHEN elem->>'id' = 'won'  THEN jsonb_set(elem, '{id}', '"closed_won"')
      WHEN elem->>'id' = 'lost' THEN jsonb_set(elem, '{id}', '"closed_lost"')
      ELSE elem
    END
    ORDER BY ord
  )
  FROM jsonb_array_elements(p.stages) WITH ORDINALITY AS t(elem, ord)
)
WHERE p.stages @> '[{"id":"won"}]' OR p.stages @> '[{"id":"lost"}]';

-- ─── from api/migrations/027_relax_template_category.sql ───
-- 027: Relax the email_templates.category CHECK so UI-created templates persist.
--
-- The template builder offers categories 'intro'/'closing'/'nurture'/'custom',
-- but the original CHECK only allowed 'outreach'/'follow_up'/'proposal'/
-- 'onboarding'/'general', so creating/editing a template from the UI failed the
-- constraint (and the store swallowed the 400, losing the row on reload).
-- Replace the constraint with the union of both sets so legacy rows stay valid
-- and the UI's categories are accepted. (templates.ts zod enum matches this set.)

DO $$
DECLARE c text;
BEGIN
  FOR c IN
    SELECT conname FROM pg_constraint
    WHERE conrelid = 'email_templates'::regclass AND contype = 'c'
  LOOP
    EXECUTE 'ALTER TABLE email_templates DROP CONSTRAINT ' || quote_ident(c);
  END LOOP;
END $$;

ALTER TABLE email_templates
  ADD CONSTRAINT email_templates_category_check
  CHECK (category IN (
    'outreach', 'follow_up', 'proposal', 'onboarding', 'general',
    'intro', 'closing', 'nurture', 'custom'
  ));

-- ─── from api/migrations/028_owner_display_name.sql ───
-- 028: Store record "owner" (assigned_to) as a display-name string, not a user-id FK.
--
-- The entire frontend treats assigned_to as a user's display NAME — the contact
-- and deal owner Selects submit `u.name`, the "my data" filter compares to
-- `currentUser.name`, list search includes the owner name, and detail views render
-- it directly. But contacts/deals/leads.assigned_to were `uuid REFERENCES users(id)`,
-- so creating/editing a record with an owner failed validation (400) and never
-- persisted. leads.assigned_to was already validated as a free string.
--
-- Align the schema with how the app actually uses the column: a text label.
-- (A future "owner-by-id" model would instead change the frontend to submit ids
-- and resolve id->name for display — deliberately not done here to avoid a broad,
-- regression-prone frontend refactor.)

-- Drop the FK constraint backing assigned_to on each table (match by column, so
-- a non-standard constraint name is still handled).
DO $$
DECLARE
  rec record;
BEGIN
  FOR rec IN
    SELECT con.conname, con.conrelid::regclass::text AS tbl
    FROM pg_constraint con
    JOIN pg_attribute att
      ON att.attrelid = con.conrelid AND att.attnum = ANY (con.conkey)
    WHERE con.contype = 'f'
      AND con.conrelid IN ('contacts'::regclass, 'deals'::regclass, 'leads'::regclass)
      AND att.attname = 'assigned_to'
  LOOP
    EXECUTE format('ALTER TABLE %s DROP CONSTRAINT %I', rec.tbl, rec.conname);
  END LOOP;
END $$;

ALTER TABLE contacts ALTER COLUMN assigned_to TYPE text USING assigned_to::text;
ALTER TABLE deals    ALTER COLUMN assigned_to TYPE text USING assigned_to::text;
ALTER TABLE leads    ALTER COLUMN assigned_to TYPE text USING assigned_to::text;

-- ─── from api/migrations/029_stage_age_and_sequence_sent_at.sql ───
-- 029: support two audit-fix features.
--
-- (B1-24) deals.stage_changed_at — "days in stage" was computed from updated_at,
-- so any unrelated edit reset the counter. Track when the stage last changed.
ALTER TABLE deals ADD COLUMN IF NOT EXISTS stage_changed_at timestamptz NOT NULL DEFAULT now();
-- Seed existing rows from updated_at (closest signal we have) instead of the
-- migration-time default, so current cards don't all reset to "0 days in stage".
UPDATE deals SET stage_changed_at = COALESCE(updated_at, created_at, now());

-- (B1-16) sequence_enrollments.last_sent_at — reply detection keyed off a Gmail
-- last_sent_thread_id that the SMTP send path never wrote, so "stop on contact
-- reply" never fired. Record the time of the last step send so reply detection
-- can match any inbound message from the contact after it (transport-independent).
ALTER TABLE sequence_enrollments ADD COLUMN IF NOT EXISTS last_sent_at timestamptz;

